import{_ as a,o,c as s,a0 as i}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Limitações Conhecidas","description":"","frontmatter":{},"headers":[],"relativePath":"operations/known-limitations.md","filePath":"operations/known-limitations.md"}'),t={name:"operations/known-limitations.md"};function n(r,e,d,c,l,p){return o(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="limitacoes-conhecidas" tabindex="-1">Limitações Conhecidas <a class="header-anchor" href="#limitacoes-conhecidas" aria-label="Permalink to &quot;Limitações Conhecidas&quot;">​</a></h1><p>Esta página documenta limitações identificadas diretamente no código-fonte do Torukr. Não são limitações inventadas — cada item foi detectado na análise do código.</p><h2 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h2><h3 id="dry-run-nao-totalmente-suportado" tabindex="-1">Dry-run não totalmente suportado <a class="header-anchor" href="#dry-run-nao-totalmente-suportado" aria-label="Permalink to &quot;Dry-run não totalmente suportado&quot;">​</a></h3><p>O comando <code>torukrctl apply --dry-run</code> existe na CLI mas o suporte do lado da API é parcial.</p><p><strong>Local no código:</strong> <code>internal/cli/commands/apply.go</code></p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> dryRun {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    output.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">PrintWarning</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Dry-run mode is not yet fully supported by the API&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Status:</strong> Warning exibido ao usuário, mas a operação é executada normalmente.</p><h3 id="enable-disable-de-nodes-usa-busca-por-nome" tabindex="-1">Enable/Disable de Nodes usa Busca por Nome <a class="header-anchor" href="#enable-disable-de-nodes-usa-busca-por-nome" aria-label="Permalink to &quot;Enable/Disable de Nodes usa Busca por Nome&quot;">​</a></h3><p>Os comandos <code>node enable</code> e <code>node disable</code> buscam o node pelo nome via query param <code>?name=</code>, mas a API não garante que o campo <code>name</code> seja indexado ou único globalmente. Em clusters com muitos nodes, isso pode ser lento.</p><p><strong>Local no código:</strong> <code>internal/cli/commands/node.go</code></p><hr><h2 id="rbac" tabindex="-1">RBAC <a class="header-anchor" href="#rbac" aria-label="Permalink to &quot;RBAC&quot;">​</a></h2><h3 id="permissoes-nao-aplicadas-em-todos-os-endpoints" tabindex="-1">Permissões não aplicadas em todos os endpoints <a class="header-anchor" href="#permissoes-nao-aplicadas-em-todos-os-endpoints" aria-label="Permalink to &quot;Permissões não aplicadas em todos os endpoints&quot;">​</a></h3><p>O sistema de RBAC (Roles, Permissions, RoleBindings) está implementado na camada de dados, mas a verificação de permissões não está aplicada em todos os handlers da API.</p><p><strong>Status:</strong> A API tem rotas de RBAC funcionais, mas a maioria dos endpoints verifica apenas autenticação (JWT válido), não autorização (se o usuário tem permissão específica).</p><p><strong>Impacto:</strong> Qualquer usuário autenticado pode executar qualquer operação.</p><hr><h2 id="logs" tabindex="-1">Logs <a class="header-anchor" href="#logs" aria-label="Permalink to &quot;Logs&quot;">​</a></h2><h3 id="streaming-de-logs-parcialmente-implementado" tabindex="-1">Streaming de logs parcialmente implementado <a class="header-anchor" href="#streaming-de-logs-parcialmente-implementado" aria-label="Permalink to &quot;Streaming de logs parcialmente implementado&quot;">​</a></h3><p>O endpoint <code>GET /namespaces/:namespace/apps/:name/logs/stream</code> está registrado nas rotas mas a implementação de streaming em tempo real pode não estar completa em todas as versões.</p><p><strong>Local no código:</strong> <code>internal/apiserver/logs/routes.go</code></p><hr><h2 id="networks" tabindex="-1">Networks <a class="header-anchor" href="#networks" aria-label="Permalink to &quot;Networks&quot;">​</a></h2><h3 id="vinculacao-explicita-de-networks-a-apps-resources" tabindex="-1">Vinculação explícita de Networks a Apps/Resources <a class="header-anchor" href="#vinculacao-explicita-de-networks-a-apps-resources" aria-label="Permalink to &quot;Vinculação explícita de Networks a Apps/Resources&quot;">​</a></h3><p>Atualmente não há um campo explícito de <code>networkRef</code> em Apps ou Resources para especificar qual rede overlay eles devem usar. A comunicação pelo overlay existe, mas a associação declarativa rede↔workload ainda está em desenvolvimento.</p><hr><h2 id="node-discovery-service-discovery" tabindex="-1">Node Discovery / Service Discovery <a class="header-anchor" href="#node-discovery-service-discovery" aria-label="Permalink to &quot;Node Discovery / Service Discovery&quot;">​</a></h2><h3 id="sem-dns-interno" tabindex="-1">Sem DNS interno <a class="header-anchor" href="#sem-dns-interno" aria-label="Permalink to &quot;Sem DNS interno&quot;">​</a></h3><p>O Torukr não provisiona um DNS interno. Containers se comunicam pelo IP do overlay (que pode mudar) em vez de nomes de serviço estáveis.</p><p><strong>Workaround:</strong> Consultar a API para obter o IP atual do recurso antes de conectar.</p><hr><h2 id="gencerts" tabindex="-1">gencerts <a class="header-anchor" href="#gencerts" aria-label="Permalink to &quot;gencerts&quot;">​</a></h2><h3 id="certificados-com-sans-fixos" tabindex="-1">Certificados com SANs fixos <a class="header-anchor" href="#certificados-com-sans-fixos" aria-label="Permalink to &quot;Certificados com SANs fixos&quot;">​</a></h3><p>O <code>gencerts</code> gera certificados com SANs pré-definidos:</p><ul><li>Servidor: <code>localhost</code>, <code>noderuntime</code>, <code>noderuntime.torukr.svc</code></li><li>Cliente: <code>controller</code>, <code>controller.torukr.svc</code></li></ul><p>Se você precisar de SANs customizados (para IPs públicos ou domínios custom), o <code>gencerts</code> não suporta isso atualmente. Seria necessário usar <code>openssl</code> diretamente.</p><hr><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><ul><li><a href="/operations/troubleshooting.html">Troubleshooting</a></li><li><a href="/reference/api.html">Referência da API</a></li><li><a href="/development/contributing.html">Contribuindo</a></li></ul>`,40)])])}const h=a(t,[["render",n]]);export{u as __pageData,h as default};
